  ffi.Pointer<BrotliEncoderState> state,
  BrotliEncoderOperation op,
  ffi.Pointer<ffi.Size> available_in,
  ffi.Pointer<ffi.Pointer<ffi.Uint8>> next_in,
  ffi.Pointer<ffi.Size> available_out,
  ffi.Pointer<ffi.Pointer<ffi.Uint8>> next_out,
  ffi.Pointer<ffi.Size> total_out,
) => _BrotliEncoderCompressStream(
  state,
  op.value,
  available_in,
  next_in,
  available_out,
  next_out,
  total_out,
);

/// Checks if encoder instance reached the final state.
///
/// @param state encoder instance
/// @returns ::BROTLI_TRUE if encoder is in a state where it reached the end of
/// the input and produced all of the output
/// @returns ::BROTLI_FALSE otherwise
@ffi.Native<ffi.Int Function(ffi.Pointer<BrotliEncoderState>)>()
external int BrotliEncoderIsFinished(ffi.Pointer<BrotliEncoderState> state);

/// Checks if encoder has more output.
