/// @param state encoder instance
/// @returns ::BROTLI_TRUE, if encoder has some unconsumed output
/// @returns ::BROTLI_FALSE otherwise
@ffi.Native<ffi.Int Function(ffi.Pointer<BrotliEncoderState>)>()
external int BrotliEncoderHasMoreOutput(ffi.Pointer<BrotliEncoderState> state);

/// Acquires pointer to internal output buffer.
///
/// This method is used to make language bindings easier and more efficient:
/// -# push data to ::BrotliEncoderCompressStream,
/// until ::BrotliEncoderHasMoreOutput returns BROTLI_TRUE
/// -# use ::BrotliEncoderTakeOutput to peek bytes and copy to language-specific
/// entity
